(588, '_elementor_notifications_data', 'a:2:{s:7:\"timeout\";i:1774379059;s:5:\"value\";s:13878:\"[{\"id\":\"angie-launch\",\"title\":\"Introducing Angie Code.\",\"description\":\"Create custom Elementor widgets, and snippets for custom site functionality from a simple description. Built natively for WordPress, and Elementor. Preview safely, refine through conversation, and publish when ready.\",\"topic\":\"Angie Code\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/angie-launch.png\",\"chipTags\":[\"New launch\"],\"link\":\"https:\\/\\/go.elementor.com\\/ai-notification-angie-launch\\/\",\"readMoreText\":\"Learn More\"},{\"id\":\"partner-program\",\"title\":\"Partner with Elementor. Grow your business.\",\"description\":\"Join to unlock exclusive access, secure visibility, benefit from marketing opportunities, and create additional revenue from the work you have already done. Join for free and start benefiting!\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/notification-partner.png\",\"chipTags\":[\"Partner Program\"],\"cta\":\"Apply now\",\"ctaLink\":\"https:\\/\\/my.elementor.com\\/agency\\/\"},{\"id\":\"manage-launch\",\"title\":\"Introducing Manage\",\"description\":\"Monitor, optimize and maintain all your sites from one centralized dashboard. Track performance, perform bulk updates and detect security risks to stay ahead of issues.\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/manage.png\",\"chipTags\":[\"New Launch\"],\"cta\":\"Start free\",\"ctaLink\":\"https:\\/\\/go.elementor.com\\/manage\\/whatsnew\"},{\"id\":\"components-3.35\",\"title\":\"Components\",\"description\":\"Build modular, reusable sections that update everywhere and decide how much control to give away to your team or clients.\",\"topic\":\"Version 4 beta\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/components-3-35.png\",\"chipTags\":[\"New Feature\"],