(1090, 1, '2017-07-28 02:41:37', '2017-07-28 02:41:37', '<p class=\"name\">[text* your-name placeholder \"Name*\"]</p>\r\n\r\n<p class=\"email\">[email* your-email placeholder \"Email*\"]</p>\r\n\r\n<p class=\"subject\">[text your-subject placeholder \"Subject\"]</p>\r\n\r\n<p class=\"message\">[textarea* your-message placeholder \"Your Message\"]</p>\r\n\r\n<p class=\"submit\">[submit \"Submit\"]</p>\n1\nBest Animal WordPress Themes Of Your Choice \"[your-subject]\"\n[your-name] <wordpress@soledad.pencidesign.com>\npencidesign@gmail.com\nFrom: [your-name] <[your-email]>\r\nSubject: [your-subject]\r\n\r\nMessage Body:\r\n[your-message]\r\n\r\n-- \r\nThis e-mail was sent from a contact form on Best Animal WordPress Themes Of Your Choice (https://soledad.pencidesign.net/soledad-animal-news)\nReply-To: [your-email]\n\n\n\n\nBest Animal WordPress Themes Of Your Choice \"[your-subject]\"\nBest Animal WordPress Themes Of Your Choice <wordpress@soledad.pencidesign.com>\n[your-email]\nMessage Body:\r\n[your-message]\r\n\r\n-- \r\nThis e-mail was sent from a contact form on Best Animal WordPress Themes Of Your Choice (https://soledad.pencidesign.net/soledad-animal-news)\nReply-To: pencidesign@gmail.com\n\n\n\nThank you for your message. It has been sent.\nThere was an error trying to send your message. Please try again later.\nOne or more fields have an error. Please check and try again.\nThere was an error trying to send your message. Please try again later.\nYou must accept the terms and conditions before sending your message.\nThe field is required.\nThe field is too long.\nThe field is too short.\nThe date format is incorrect.\nThe date is before the earliest one allowed.\nThe date is after the latest one allowed.\nThere was an unknown error uploading the file.\nYou are not allowed to upload files of this type.\nThe file is too big.\nThere was an error uploading the file.\nThe number format is invalid.\nThe number is smaller than the minimum allowed.\nThe number is larger than the maximum allowed.\nThe answer to the quiz is incorrect.\nYour entered code is incorrect.\nThe e-mail address entered is invalid.\nThe URL is invalid.\nThe telephone number is invalid.', 'contact', '', 'publish', 'closed', 'closed', '', 'contact', '', '', '2026-03-24 17:23:05', '2026-03-24 17:23:05', '', 0, 'https://soledad.pencidesign.net/soledad-animal-news/?post_type=wpcf7_contact_form&amp;p=1090', 0, 'wpcf7_contact_form', '', 0),
